UPDATE pr_heat_dtu_archive
SET status = #{dtuStatus}
WHERE dtu_num IN (
    SELECT dtu_num FROM pr_heat_valve_archive
    WHERE meter_num = #{meterNum}

        AND meter_arc_name = #{meterInfo}

)

UPDATE pr_heat_dtu_archive
SET status = #{dtuStatus}
WHERE dtu_num IN (
    SELECT dtu_num FROM pr_heat_unit_valve_archive
    WHERE meter_num = #{meterNum}

        AND meter_arc_name = #{meterInfo}

)

UPDATE pr_heat_dtu_archive
SET status = #{dtuStatus}
WHERE dtu_num IN (
    SELECT dtu_num FROM pr_heat_hot_archive
    WHERE meter_num = #{meterNum}
)

UPDATE pr_heat_dtu_archive
SET status = #{dtuStatus}
WHERE dtu_num IN (
    SELECT dtu_num FROM pr_heat_unit_hot_archive
    WHERE meter_num = #{meterNum}
)

UPDATE pr_house
SET valve_open = #{actualStatus},
    in_temp = #{inTemp},
    out_temp = #{outTemp}
WHERE id IN (
    SELECT house_id FROM pr_heat_valve_archive
    WHERE meter_num = #{meterNum}

        AND meter_arc_name = #{meterInfo}

)

UPDATE pr_unit
SET valve_open = #{actualStatus},
    in_temp = #{inTemp},
    out_temp = #{outTemp}
WHERE id IN (
    SELECT unit_id FROM pr_heat_unit_valve_archive
    WHERE meter_num = #{meterNum}

        AND meter_arc_name = #{meterInfo}

)

UPDATE pr_house
SET room_temp = #{temperature}
WHERE id IN (
    SELECT house_id FROM pr_heat_temp_archive
    WHERE meter_num = #{meterNum}
)

UPDATE pr_house
SET cur_flow = #{flowRate}
WHERE id IN (
    SELECT house_id FROM pr_heat_hot_archive
    WHERE meter_num = #{meterNum}
)

UPDATE ht_tasks_perform
SET instruction_status = #{valveStatus},
    send_time = NOW()
WHERE meter_num = #{meterNum}
  AND instruction_type = #{command}
  AND status IN (0, 1, 2)
  AND id = #{guid}

UPDATE ht_scope
SET status = #{valveStatus}
WHERE meter_num = #{meterNum}
  AND tasks_id IN (
    SELECT tasks_id FROM ht_tasks_perform
    WHERE status = '2'

        AND id = #{guid}

)

UPDATE pr_heat_valve_archive
SET chan_num = #{channelNum},
    update_time = NOW()
WHERE meter_num = #{meterNum}
  AND meter_arc_name = #{meterInfo}

UPDATE pr_heat_unit_valve_archive
SET update_time = NOW()
WHERE meter_num = #{meterNum}

UPDATE pr_heat_unit_valve_archive
SET chan_num = #{channelNum},
    update_time = NOW()
WHERE meter_num = #{meterNum}
  AND meter_arc_name = #{meterInfo}

UPDATE pr_heat_hot_archive
SET dtu_num_status = #{status}
WHERE dtu_num = #{dtuNum}

UPDATE pr_heat_unit_hot_archive
SET dtu_num_status = #{status}
WHERE dtu_num = #{dtuNum}

UPDATE pr_heat_valve_archive
SET dtu_num_status = #{status}
WHERE dtu_num = #{dtuNum}

UPDATE pr_heat_unit_valve_archive
